// NQxb_Artifact_Promote_v1__Normalize_request
// Purpose: Validate promote request shape, enforce required fields,
//          normalize selector, generate request_id.
//
// CRITICAL:
// - transition/reason arrive via artifact_payload due to ExecuteWorkflowTrigger contract
// - NEVER expect them top-level here
// - Output must surface transition/reason top-level for downstream nodes

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = (Math.random() * 16) | 0;
    const v = (c === 'x') ? r : ((r & 0x3) | 0x8);
    return v.toString(16);
  });
}

const j = $json ?? {};

const gw_action = j.gw_action ?? "artifact.promote";
const gw_workspace_id = j.gw_workspace_id ?? j.workspace_id ?? null;
const artifact_type = j.artifact_type ?? null;
const artifact_id = j.artifact_id ?? null;

// ✅ FIX: read from artifact_payload
const transition_raw = j.artifact_payload?.transition ?? null;
const reason_raw = j.artifact_payload?.reason ?? null;

// Optional passthrough
const actor_user_id_raw = j.actor_user_id ?? null;

const selector_in = (j.selector && typeof j.selector === "object") ? j.selector : {};
const hydrate = selector_in.hydrate === true;

const transition =
  (typeof transition_raw === "string") ? transition_raw.trim() : "";

const reason =
  (typeof reason_raw === "string") ? reason_raw.trim() : "";

// Normalize actor_user_id
const actor_user_id =
  (typeof actor_user_id_raw === "string" && actor_user_id_raw.trim().length > 0)
    ? actor_user_id_raw.trim()
    : null;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

const fail = (code, message, details = {}) => [{
  json: {
    ok: false,
    _gw_route: "error",
    gw_action: "artifact.promote",
    gw_workspace_id,
    artifact_type,
    artifact_id,
    error: { code, message, details },
    timestamp: new Date().toISOString(),
  },
}];

// ---- Validation ----
if (!gw_workspace_id) {
  return fail("VALIDATION_ERROR", "gw_workspace_id is required");
}
if (!artifact_type) {
  return fail("VALIDATION_ERROR", "artifact_type is required");
}
if (!artifact_id) {
  return fail("VALIDATION_ERROR", "artifact_id is required");
}
if (!transition) {
  return fail("VALIDATION_ERROR", "transition is required", {
    source: "artifact_payload.transition",
  });
}
if (!reason || reason.length < 1 || reason.length > 280) {
  return fail("VALIDATION_ERROR", "reason is required (1..280 chars)", {
    received_length: reason.length,
  });
}
if (actor_user_id && !UUID_RE.test(actor_user_id)) {
  return fail("VALIDATION_ERROR", "actor_user_id must be a valid UUID when provided", {
    actor_user_id,
  });
}

const request_id = uuidv4();

// ---- Canonical output ----
return [{
  json: {
    ok: true,
    gw_action: "artifact.promote",
    gw_workspace_id,
    artifact_type: String(artifact_type),
    artifact_id: String(artifact_id),

    // ✅ surface for downstream
    transition,
    reason,

    selector: { hydrate },
    request_id,
    actor_user_id,
  },
}];

// NQxb_Artifact_Promote_v1__Resolve_Transition
// Purpose: Map a locked transition allow-list -> from_state/to_state, or reject.
//
// QPM PHASE 2 UPDATE (2026-02-01):
// - REMOVED archive_to_tree: Archive is now terminal (irreversible)
// - Only forward transitions allowed: seed->sapling->tree->archive
//
// IMPORTANT (n8n): Do NOT emit top-level reserved keys like `error`.
// Always wrap output under `{ json: ... }`.

const input = $json;

// FIX: Contract-safe fallback — transition may arrive inside artifact_payload
const transition = (
  input.transition ??
  input.artifact_payload?.transition ??
  ""
).toString().trim();

// QPM Phase 2: Only forward transitions allowed
// REMOVED: archive_to_tree (archive is terminal)
const map = {
  seed_to_sapling: { from_state: "seed", to_state: "sapling" },
  sapling_to_tree: { from_state: "sapling", to_state: "tree" },
  tree_to_archive: { from_state: "tree", to_state: "archive" },
};

const resolved = map[transition];

if (!resolved) {
  return [
    {
      json: {
        ...input,
        ok: false,
        _gw_route: "error",
        error: {
          code: "LIFECYCLE_TRANSITION_NOT_ALLOWED",
          message: `Transition not allowed: '${transition || "(empty)"}'`,
          details: {
            transition: transition || null,
            allowed: Object.keys(map),
          },
        },
      },
    },
  ];
}

return [
  {
    json: {
      ...input,
      ok: true,
      _gw_route: input._gw_route ?? "ok",
      from_state: resolved.from_state,
      to_state: resolved.to_state,
    },
  },
];

// NQxb_Artifact_Promote_v1__Enforce_Verified_State
// Purpose: Ensure artifact exists and lifecycle_status matches from_state.
// IMPORTANT: lifecycle_status MUST come from Verify_Current_State (pre-update),
// not from merged $json (which may already be post-update).
//
// QPM PHASE 2 UPDATE (2026-02-01):
// - Now also captures spine.summary for QPM validation downstream

const input = $json;

// --- Required fields from merged input ---
const artifactId = input.artifact_id ?? null;
const fromState = (input.from_state ?? "").toString().trim();

// --- Pull VERIFIED state directly from Verify_Current_State ---
const verifiedNode = $node["NQxb_Artifact_Promote_v1__Verify_Current_State"];
const verifiedRaw = verifiedNode?.json ?? null;

// Supabase "get" may return object OR array
const verified = Array.isArray(verifiedRaw)
  ? verifiedRaw[0] ?? null
  : verifiedRaw;

const actual = verified?.lifecycle_status ?? null;

// Capture summary for QPM validation (seed_to_sapling check)
const summary = verified?.summary ?? null;

// --- Guards ---

if (!artifactId) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "ARTIFACT_NOT_FOUND",
        message: "artifact_id missing after DB verify.",
        details: { artifact_id: null }
      }
    }
  }];
}

if (!fromState) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "FROM_STATE_MISSING",
        message: "from_state missing after Resolve_Transition.",
        details: { from_state: input.from_state ?? null }
      }
    }
  }];
}

if (!actual) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "LIFECYCLE_STATE_UNKNOWN",
        message: "Could not determine current lifecycle state from DB verify.",
        details: {
          artifact_id: artifactId,
          verified_row: verified ?? null
        }
      }
    }
  }];
}

// --- Enforce pre-update lifecycle correctness ---

if (actual !== fromState) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "LIFECYCLE_STATE_MISMATCH",
        message: `Expected lifecycle '${fromState}', got '${actual}'.`,
        details: {
          artifact_id: artifactId,
          expected_from_state: fromState,
          actual_lifecycle_status: actual
        }
      }
    }
  }];
}

// --- Success: verified correctly ---
// Include summary for QPM validation

return [{
  json: {
    ...input,
    ok: true,
    _gw_route: input._gw_route ?? "ok",
    _spine_summary: summary,
    _lifecycle_verify: {
      artifact_id: artifactId,
      verified_from_state: fromState,
      current_lifecycle_status: actual
    }
  }
}];

